    ["age"] = { -- Hidden age prompt (First %s: First name / Second %s: Residence / *: Age)
        [1] = "%s ב-%s, אנליסט פיננסי אתי שמקדם השקעות ברות קיימא לעולם ירוק יותר. עם תחושת אחריות עמוקה, אנליסט מנוסה זה, בן *, מתאים את מטרותיהם הכלכליות של לקוחותיו לשמירה על הסביבה.",
        [2] = "%s מ-%s, מצליח לפתור אתגרים מסובכים בתחום המיסוי עבור לקוחות עסקיים. עם כישורים אנליטיים חדים וניסיון רב, מומחה מיסוי זה, בן *, מתמודד בקלות עם מצבים כלכליים מורכבים.",
        [3] = "%s ב-%s, בונה שותפויות מתמשכות עם ארגוני צדקה, מקדמת השפעה חברתית חיובית. עם לב לפילנתרופיה וניסיון רב, אסטרטג פילנתרופי זה, בן *, משתמש במומחיותו הפיננסית להגברת האפקטיביות של יוזמות חברתיות.",
        [4] = "%s מ-%s, הוא חלוץ בהשקעות שמשנה את התעשייה באמצעות טכנולוגיות מתקדמות. בגיל *, משקיע חזוני זה מדמיין עידן חדש של שירותי השקעות ממוקדי לקוח, הנתמכים על ידי התקדמות טכנולוגית.",
        [5] = "%s ב-%s, מתמחה במיזוגים ורכישות ומארגן עסקאות מוצלחות עבור לקוחות עסקיים. עם עין חדה להזדמנויות ושנים של ניסיון, מומחה המיזוגים והרכישות הזה, בן *, ממקסם את הערך עבור כל בעלי העניין בעסקאות מורכבות.",
        [6] = "%s מ-%s, מעניק עוצמה ליזמים מגוונים, וסוגר פערים פיננסיים עבור קהילות שאינן מיוצגות מספיק. עם מחויבות למימון כוללני וניסיון רב, יועץ הפיתוח העסקי הזה, בן *, מקדם שוויון כלכלי עבור כל בעלי העסקים השאפתנים.",
        [7] = "%s ב-%s, עוזר למשפחות להבטיח את עתידן באמצעות תכנון ירושה זהיר. עם גישה אמפתית ושנים של ניסיון, מתכנן הירושה הזה, בן *, מספק ייעוץ פיננסי מותאם אישית להבטחת העברה חלקה של עושר בין הדורות.",
        [8] = "%s מ-%s, בן *, הוא יועץ פיננסי מנוסה בעל ניסיון רב. עם הבנה מעמיקה של תעשיית הפיננסים ושנים של פרקטיקה מוצלחת, יועץ זה ממשיך להיות כוח מניע בתעשייה.",
        [9] = "%s ב-%s, הוא מנהל עושר אמין שמגדל ושומר על נכסי הלקוחות לדורות הבאים. עם התמקדות ברווחה ארוכת טווח וניסיון רב, מנהל העושר הזה, בן *, מגן על ירושותיהם הכלכליות של לקוחותיו.",
        [10] = "%s מ-%s, הוא ארכיטקט פתרונות בנקאות חכם טכנולוגית שמשתמש בחדשנות דיגיטלית לשיפור חוויית הלקוח. עם אהבה לחדשנות וניסיון רב, ארכיטקט הפתרונות הזה מוביל פתרונות בנקאות מתקדמים למסע לקוח ללא תקלות.",
        [11] = "%s ב-%s, מקדם חינוך פיננסי בקרב צעירים, מעורר את הדור הבא של משקיעים חכמים. עם מחויבות לחינוך פיננסי וניסיון רב, מחנך פיננסי זה, בן *, מעצים את המוחות הצעירים לקבלת החלטות פיננסיות מושכלות.",
